CREATE TABLE IF NOT EXISTS `system_settings` (`key` VARCHAR(100) NOT NULL, `value` TEXT NOT NULL, `isSecret` BOOLEAN NOT NULL DEFAULT false, `updatedAt` DATETIME(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3) ON UPDATE CURRENT_TIMESTAMP(3), `updatedBy` INTEGER NULL, PRIMARY KEY (`key`)) DEFAULT CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;